proof_block:
// The synthetic ensures has the shape `BIG_CONJ ==> det_equal(...)`, i.e. the
// original function's ensures (for both post1 and post2) are the ANTECEDENT
// of an implication — they are NOT free hypotheses in the proof body. That
// is why the previous attempt's bare `assert forall ... by { assert(...) }`
// blocks failed: inside the by-body only the function precondition is in
// scope, and the inner `assert(post1.get_proc(p) =~= pre.get_proc(p))`
// cannot be discharged.
//
// Fix: gate the proof on `if BIG_CONJ { ... }`. Inside the branch every
// ensures-conjunct is a real hypothesis; outside the branch the implication
// is trivially true so the postcondition holds for free. We additionally
// broadcast `reveal_process_manager_wf` so that `wf()` unfolds to the
// component-wise invariants we need (perms_wf carries `addr() == k` and
// `is_init()`, which lifts per-key value equality to per-key PointsTo
// equality and therefore to full perm-map extensional equality).

broadcast use ProcessManager::reveal_process_manager_wf;

let target_endpoint = pre_self_.get_thread(thread_ptr)
    .endpoint_descriptors@[endpoint_index as int].unwrap();

if ({
    &&& post1_self_.wf()
    &&& post1_self_.page_closure() =~= pre_self_.page_closure()
    &&& post1_self_.proc_dom() =~= pre_self_.proc_dom()
    &&& post1_self_.endpoint_dom() == pre_self_.endpoint_dom()
    &&& post1_self_.container_dom() == pre_self_.container_dom()
    &&& post1_self_.thread_dom() == pre_self_.thread_dom()
    &&& (forall|p_ptr: ProcPtr|
            #![trigger post1_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr) ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    &&& (forall|container_ptr: ContainerPtr|
            #![trigger post1_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr) ==> post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    &&& (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    &&& (forall|e_ptr: EndpointPtr|
            #![trigger post1_self_.get_endpoint(e_ptr)]
            post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_endpoint ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    &&& post1_self_.get_thread(thread_ptr).endpoint_descriptors =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors
    &&& post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload
    &&& post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED
    &&& post1_self_.get_endpoint(target_endpoint).queue_state == queue_state
    &&& post1_self_.get_endpoint(target_endpoint).owning_threads == pre_self_.get_endpoint(target_endpoint).owning_threads
    &&& post1_self_.get_endpoint(target_endpoint).queue@ == pre_self_.get_endpoint(target_endpoint).queue@.push(thread_ptr)
    &&& post2_self_.wf()
    &&& post2_self_.page_closure() =~= pre_self_.page_closure()
    &&& post2_self_.proc_dom() =~= pre_self_.proc_dom()
    &&& post2_self_.endpoint_dom() == pre_self_.endpoint_dom()
    &&& post2_self_.container_dom() == pre_self_.container_dom()
    &&& post2_self_.thread_dom() == pre_self_.thread_dom()
    &&& (forall|p_ptr: ProcPtr|
            #![trigger post2_self_.get_proc(p_ptr)]
            pre_self_.proc_dom().contains(p_ptr) ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    &&& (forall|container_ptr: ContainerPtr|
            #![trigger post2_self_.get_container(container_ptr)]
            pre_self_.container_dom().contains(container_ptr) ==> post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    &&& (forall|t_ptr: ThreadPtr|
            #![trigger pre_self_.get_thread(t_ptr)]
            pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    &&& (forall|e_ptr: EndpointPtr|
            #![trigger post2_self_.get_endpoint(e_ptr)]
            post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_endpoint ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    &&& post2_self_.get_thread(thread_ptr).endpoint_descriptors =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors
    &&& post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload
    &&& post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED
    &&& post2_self_.get_endpoint(target_endpoint).queue_state == queue_state
    &&& post2_self_.get_endpoint(target_endpoint).owning_threads == pre_self_.get_endpoint(target_endpoint).owning_threads
    &&& post2_self_.get_endpoint(target_endpoint).queue@ == pre_self_.get_endpoint(target_endpoint).queue@.push(thread_ptr)
}) {
    // Inside this branch every ensures-conjunct holds as a real hypothesis.

    // === Perm-map domain alignment ===
    // proc_dom / container_dom / thread_dom / endpoint_dom are inline aliases
    // for *_perms@.dom(), so the ensures give us domain equality directly.
    assert((post1_self_.container_perms)@.dom() =~= (post2_self_.container_perms)@.dom());
    assert((post1_self_.process_perms)@.dom() =~= (post2_self_.process_perms)@.dom());
    assert((post1_self_.thread_perms)@.dom() =~= (post2_self_.thread_perms)@.dom());
    assert((post1_self_.endpoint_perms)@.dom() =~= (post2_self_.endpoint_perms)@.dom());

    // === Per-key get_X equality across the two runs ===
    // Each get_X spec fn is inlined as `&perms@[k].value()`, so the per-side
    // ensures-forall pins post*_.get_X(k) to pre_self_.get_X(k). Chaining
    // through pre gives post1.get_X(k) == post2.get_X(k) (value equality).
    assert forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) == post2_self_.get_proc(p_ptr) by {
        // Each of the next two asserts mentions the single-state trigger
        // term that fires the corresponding ensures-forall.
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    }
    assert forall|c_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
        pre_self_.container_dom().contains(c_ptr) implies
        post1_self_.get_container(c_ptr) == post2_self_.get_container(c_ptr) by {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    }
    assert forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) implies
        post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr) by {
        if t_ptr == thread_ptr {
            // Target thread's three observable fields are pinned by the
            // ensures; the other fields of `Thread` are forced equal because
            // both posts satisfy `wf()` and were derived from the same
            // pre-thread modulo the same triple of changes.
            assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
                =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);
            assert(post1_self_.get_thread(thread_ptr).ipc_payload
                =~= post2_self_.get_thread(thread_ptr).ipc_payload);
            assert(post1_self_.get_thread(thread_ptr).state
                == post2_self_.get_thread(thread_ptr).state);
        } else {
            // Off-target: both posts equal pre at t_ptr (same trigger fires).
            assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
            assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
        }
    }
    assert forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
        post1_self_.endpoint_dom().contains(e_ptr) implies
        post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr) by {
        // post2_self_.endpoint_dom() == pre_self_.endpoint_dom() == post1_self_.endpoint_dom()
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        if e_ptr == target_endpoint {
            assert(post1_self_.get_endpoint(target_endpoint).queue_state
                == post2_self_.get_endpoint(target_endpoint).queue_state);
            assert(post1_self_.get_endpoint(target_endpoint).owning_threads
                == post2_self_.get_endpoint(target_endpoint).owning_threads);
            assert(post1_self_.get_endpoint(target_endpoint).queue@
                == post2_self_.get_endpoint(target_endpoint).queue@);
        } else {
            assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
            assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        }
    }

    // === Lift per-key get_X equality to map extensional equality on *_perms@ ===
    // For each perm map, both posts have the same domain (above) and per-key
    // values (above). `wf()` (revealed via the broadcast) carries the
    // `is_init()` and `addr() == k` invariants for every key in the domain,
    // so the per-key PointsTo agree, which gives full map extensional
    // equality via `=~=`.
    assert forall|c_ptr: ContainerPtr|
        #![trigger (post1_self_.container_perms)@[c_ptr], (post2_self_.container_perms)@[c_ptr]]
        (post1_self_.container_perms)@.dom().contains(c_ptr) implies
        (post1_self_.container_perms)@[c_ptr] == (post2_self_.container_perms)@[c_ptr] by {
        assert(pre_self_.container_dom().contains(c_ptr));
        assert(post1_self_.container_dom().contains(c_ptr));
        assert(post2_self_.container_dom().contains(c_ptr));
        assert(post1_self_.get_container(c_ptr) == post2_self_.get_container(c_ptr));
    }
    assert((post1_self_.container_perms)@ =~= (post2_self_.container_perms)@);

    assert forall|p_ptr: ProcPtr|
        #![trigger (post1_self_.process_perms)@[p_ptr], (post2_self_.process_perms)@[p_ptr]]
        (post1_self_.process_perms)@.dom().contains(p_ptr) implies
        (post1_self_.process_perms)@[p_ptr] == (post2_self_.process_perms)@[p_ptr] by {
        assert(pre_self_.proc_dom().contains(p_ptr));
        assert(post1_self_.proc_dom().contains(p_ptr));
        assert(post2_self_.proc_dom().contains(p_ptr));
        assert(post1_self_.get_proc(p_ptr) == post2_self_.get_proc(p_ptr));
    }
    assert((post1_self_.process_perms)@ =~= (post2_self_.process_perms)@);

    assert forall|t_ptr: ThreadPtr|
        #![trigger (post1_self_.thread_perms)@[t_ptr], (post2_self_.thread_perms)@[t_ptr]]
        (post1_self_.thread_perms)@.dom().contains(t_ptr) implies
        (post1_self_.thread_perms)@[t_ptr] == (post2_self_.thread_perms)@[t_ptr] by {
        assert(pre_self_.thread_dom().contains(t_ptr));
        assert(post1_self_.thread_dom().contains(t_ptr));
        assert(post2_self_.thread_dom().contains(t_ptr));
        assert(post1_self_.get_thread(t_ptr) == post2_self_.get_thread(t_ptr));
    }
    assert((post1_self_.thread_perms)@ =~= (post2_self_.thread_perms)@);

    assert forall|e_ptr: EndpointPtr|
        #![trigger (post1_self_.endpoint_perms)@[e_ptr], (post2_self_.endpoint_perms)@[e_ptr]]
        (post1_self_.endpoint_perms)@.dom().contains(e_ptr) implies
        (post1_self_.endpoint_perms)@[e_ptr] == (post2_self_.endpoint_perms)@[e_ptr] by {
        assert(pre_self_.endpoint_dom().contains(e_ptr));
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(post1_self_.get_endpoint(e_ptr) == post2_self_.get_endpoint(e_ptr));
    }
    assert((post1_self_.endpoint_perms)@ =~= (post2_self_.endpoint_perms)@);

    // === Result-tuple equality (both `()`) ===
    assert(r1 == r2);
}
